#include <bits/stdc++.h>
using namespace std;
int n;
string s;
map<string,int> mp;
int main() {
	cin>>n;
	cin >> s;
	for(int l = 1; l <= n; ++l) {
		int f = 1;
		mp.clear();
		for(int i=0, j = i + l - 1; i < n && j < n; ++i, j = i + l - 1) {
			string x = "";
			for(int k=i; k<=j; ++k) {
				x+=s[k];
			}
			if(mp[x] == 1) {
				f=0;
				break;
			}
			mp[x]=1;
		}
		if(f) {
			cout<<l;
			return 0;
		}
	}
	return 0;
}
